To enable vector search queries on your data,
you must create a vector search index on your
collection.

Complete the following steps to create an index on the
`sample_db.embeddings` collection that specifies the
`embedding` field as the [index definition](avs-types-vector-search) type
and the similarity measure as `dotProduct`.

- Paste the following code to add a `CreateVectorIndex` function to
  your `DataService` class in `DataService.cs`.

  ```csharp
  namespace MyCompany.Embeddings;

  using MongoDB.Driver;
  using MongoDB.Bson;

  public class DataService
  {
      private static readonly string? ConnectionString = Environment.GetEnvironmentVariable("MONGODB_URI");
      private static readonly MongoClient Client = new MongoClient(ConnectionString);
      private static readonly IMongoDatabase Database = Client.GetDatabase("sample_db");
      private static readonly IMongoCollection<BsonDocument> Collection = Database.GetCollection<BsonDocument>("embeddings");

      public async Task AddDocumentsAsync(Dictionary<string, float[]> embeddings)
      {
          // Method details...
      }

      public void CreateVectorIndex()
      {
          try
          {
              var searchIndexView = Collection.SearchIndexes;
              var name = "vector_index";

              var model = new CreateVectorSearchIndexModel<Document>(
                  d => d.Embedding,
                  name,
                  VectorSimilarity.DotProduct,
                  <dimensions>);

              searchIndexView.CreateOne(model);
              Console.WriteLine($"New search index named {name} is building.");
              // Polling for index status
              Console.WriteLine("Polling to check if the index is ready.");
              bool queryable = false;
              while (!queryable)
              {
                  var indexes = searchIndexView.List();
                  foreach (var index in indexes.ToEnumerable())
                  {
                      if (index["name"] == name)
                      {
                          queryable = index["queryable"].AsBoolean;
                      }
                  }
                  if (!queryable)
                  {
                      Thread.Sleep(5000);
                  }
              }
              Console.WriteLine($"{name} is ready for querying.");
          }
          catch (Exception e)
          {
              Console.WriteLine($"Exception: {e.Message}");
          }
      }
  }
  ```

- Replace the `<dimensions>` placeholder value with `1024` if you
  used Voyage AI or the open-source model and `1536` if you used the model from
  OpenAI.

- Update the code in your `Program.cs`.

  Remove the code that populated the initial documents, and replace it
  with the following code to create the index:

  ```csharp
  using MyCompany.Embeddings;

  var dataService = new DataService();
  dataService.CreateVectorIndex();

  ```

- Save the file, and then compile and run your project to create the index:

  **Input:**

  ```
  dotnet run MyCompany.Embeddings
  ```

  **Output:**

  ```
  New search index named vector_index is building.
  Polling to check if the index is ready. This may take up to a minute.
  vector_index is ready for querying.
  ```

> **Note:** The index should take about one minute to build. While it builds,
> the index is in an [initial sync process](troubleshoot-initial-sync)
> state. When it finishes building, you can start querying the data
> in your collection.

To learn more, see [Create a MongoDB Vector Search Index](avs-create-index).

- Paste the following code to add a `PerformVectorQuery` function
  to your `DataService` class in `DataService.cs`.

  To run a vector search query, generate a
  [query vector](vectorSearch-agg-pipeline-options)
  to pass into your aggregation pipeline.

  For example, this code does the following:

  - Creates a query embedding using your defined embedding function.

  - Uses this embedding in the `queryVector` field and specifies the path to query.

  - Uses [$vectorSearch](pipe.$vectorSearch) to perform an [Exact Nearest Neighbor (ENN)](vectorSearch-enn) search.

  - Returns semantically similar documents ranked by relevance with their
    [vector search score](vectorSearch-agg-pipeline-score).

  ```csharp
  namespace MyCompany.Embeddings;

  using MongoDB.Driver;
  using MongoDB.Bson;

  public class DataService
  {
      private static readonly string? ConnectionString = Environment.GetEnvironmentVariable("MONGODB_URI");
      private static readonly MongoClient Client = new MongoClient(ConnectionString);
      private static readonly IMongoDatabase Database = Client.GetDatabase("sample_db");
      private static readonly IMongoCollection<BsonDocument> Collection = Database.GetCollection<BsonDocument>("embeddings");

      public async Task AddDocumentsAsync(Dictionary<string, float[]> embeddings)
      {
          // Method details...
      }

      public void CreateVectorIndex()
      {
          // Method details...
      }

      public List<BsonDocument>? PerformVectorQuery(float[] vector)
      {
          var vectorSearchStage = new BsonDocument
          {
              {
                  "$vectorSearch",
                  new BsonDocument
                  {
                      { "index", "vector_index" },
                      { "path", "embedding" },
                      { "queryVector", new BsonArray(vector) },
                      { "exact", true },
                      { "limit", 5 }
                  }
              }
          };
          var projectStage = new BsonDocument
          {
              {
                  "$project",
                  new BsonDocument
                  {
                      { "_id", 0 },
                      { "text", 1 },
                      { "score", 
                          new BsonDocument
                          {
                              { "$meta", "vectorSearchScore"}
                          }
                      }
                  }
              }
          };
          var pipeline = new[] { vectorSearchStage, projectStage };
          return Collection.Aggregate<BsonDocument>(pipeline).ToList();
      }
  }
  ```

