      {
          // Method details...
      }

      public void CreateVectorIndex()
      {
          // Method details...
      }

      public List<BsonDocument>? PerformVectorQuery(float[] vector)
      {
          var vectorSearchStage = new BsonDocument
          {
              {
                  "$vectorSearch",
                  new BsonDocument
                  {
                      { "index", "vector_index" },
                      { "path", "embeddings" },
                      { "queryVector", new BsonArray(vector) },
                      { "exact", true },
                      { "limit", 5 }
                  }
              }
          };
          var projectStage = new BsonDocument
          {
              {
                  "$project",
                  new BsonDocument
                  {
