To enable vector search queries on your data,
you must create a vector search index on your
collection.

Complete the following steps to create an index on the
`sample_db.embeddings` collection that specifies the
`embedding` field as the [index definition](avs-types-vector-search) type
and the similarity measure as `dotProduct`.

- Create a file named named `create-index.go` and paste the following code.

  ```go
  package main
  import (
  	"context"
  	"fmt"
  	"log"
  	"os"
  	"time"
  	"github.com/joho/godotenv"
  	"go.mongodb.org/mongo-driver/v2/bson"
  	"go.mongodb.org/mongo-driver/v2/mongo"
  	"go.mongodb.org/mongo-driver/v2/mongo/options"
  )
  func main() {
  	ctx := context.Background()
  	if err := godotenv.Load(); err != nil {
  		log.Println("no .env file found")
  	}
  	// Connect to your MongoDB deployment
  	uri := os.Getenv("MONGODB_URI")
  	if uri == "" {
  		log.Fatal("set your 'MONGODB_URI' environment variable.")
  	}
  	clientOptions := options.Client().ApplyURI(uri)
  	client, err := mongo.Connect(clientOptions)
  	if err != nil {
  		log.Fatalf("failed to connect to the server: %v", err)
  	}
  	defer func() { _ = client.Disconnect(ctx) }()
  	// Set the namespace
  	coll := client.Database("sample_db").Collection("embeddings")
  	indexName := "vector_index"
  	opts := options.SearchIndexes().SetName(indexName).SetType("vectorSearch")
  	type vectorDefinitionField struct {
  		Type          string `bson:"type"`
  		Path          string `bson:"path"`
  		NumDimensions int    `bson:"numDimensions"`
  		Similarity    string `bson:"similarity"`
  	}
  	type vectorDefinition struct {
  		Fields []vectorDefinitionField `bson:"fields"`
  	}
  	indexModel := mongo.SearchIndexModel{
  		Definition: vectorDefinition{
  			Fields: []vectorDefinitionField{{
  				Type:          "vector",
  				Path:          "embedding",
  				NumDimensions: 3072,
  				Similarity:    "dotProduct"}},
  		},
  		Options: opts,
  	}
  	log.Println("Creating the index.")
  	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, indexModel)
  	if err != nil {
  		log.Fatalf("failed to create the search index: %v", err)
  	}
  	// Await the creation of the index.
  	log.Println("Polling to confirm successful index creation.")
  	searchIndexes := coll.SearchIndexes()
  	var doc bson.Raw
  	for doc == nil {
  		cursor, err := searchIndexes.List(ctx, options.SearchIndexes().SetName(searchIndexName))
  		if err != nil {
  			fmt.Errorf("failed to list search indexes: %w", err)
  		}
  		if !cursor.Next(ctx) {
  			break
  		}
  		name := cursor.Current.Lookup("name").StringValue()
  		queryable := cursor.Current.Lookup("queryable").Boolean()
  		if name == searchIndexName && queryable {
  			doc = cursor.Current
  		} else {
  			time.Sleep(5 * time.Second)
  		}
  	}
  	log.Println("Name of Index Created: " + searchIndexName)
  }

  ```

- Replace the `<dimensions>` placeholder value with `1024` if you
  used Voyage AI or the open-source model and `1536` if you used the model from
  OpenAI.

- Save the file, then run the following command:

  **Input:**

  ```
  go run create-index.go
  ```

  **Output:**

  ```
  2024/10/09 17:38:51 Creating the index.
  2024/10/09 17:38:52 Polling to confirm successful index creation.
  2024/10/09 17:39:22 Name of Index Created: vector_index
  ```

> **Note:** The index should take about one minute to build. While it builds,
> the index is in an [initial sync process](troubleshoot-initial-sync)
> state. When it finishes building, you can start querying the data
> in your collection.

To learn more, see [Create a MongoDB Vector Search Index](avs-create-index).

- Create a file named named `vector-query.go` and paste the following code.

  To run a vector search query, generate a
  [query vector](vectorSearch-agg-pipeline-options)
  to pass into your aggregation pipeline.

  For example, this code does the following:

  - Creates a query embedding using your defined embedding function.

  - Uses this embedding in the `queryVector` field and specifies the path to query.

  - Uses [$vectorSearch](pipe.$vectorSearch) to perform an [Exact Nearest Neighbor (ENN)](vectorSearch-enn) search.

  - Returns semantically similar documents ranked by relevance with their
    [vector search score](vectorSearch-agg-pipeline-score).

  Open-Source

  ```go
  package main

  import (
  	"context"
  	"fmt"
  	"log"
  	"my-embeddings-project/common"
  	"os"

  	"github.com/joho/godotenv"
  	"go.mongodb.org/mongo-driver/v2/bson"
  	"go.mongodb.org/mongo-driver/v2/mongo"
  	"go.mongodb.org/mongo-driver/v2/mongo/options"
  )

  type TextAndScore struct {
  	Text  string  `bson:"text"`
  	Score float32 `bson:"score"`
  }

  func main() {
  	ctx := context.Background()

  	// Connect to your MongoDB deployment
  	if err := godotenv.Load(); err != nil {
  		log.Println("no .env file found")
  	}

  	// Connect to your MongoDB deployment
  	uri := os.Getenv("MONGODB_URI")
  	if uri == "" {
  		log.Fatal("set your 'MONGODB_URI' environment variable.")
  	}
  	clientOptions := options.Client().ApplyURI(uri)
  	client, err := mongo.Connect(clientOptions)
  	if err != nil {
  		log.Fatalf("failed to connect to the server: %v", err)
  	}
  	defer func() { _ = client.Disconnect(ctx) }()

  	// Set the namespace
  	coll := client.Database("sample_db").Collection("embeddings")

  	query := "ocean tragedy"
  	queryEmbedding := common.GetEmbeddings([]string{query})

  	pipeline := mongo.Pipeline{
  		bson.D{
  			{"$vectorSearch", bson.D{
  				{"queryVector", queryEmbedding[0]},
  				{"index", "vector_index"},
  				{"path", "embedding"},
  				{"exact", true},
  				{"limit", 5},
  			}},
  		},
  		bson.D{
  			{"$project", bson.D{
  				{"_id", 0},
  				{"text", 1},
  				{"score", bson.D{
  					{"$meta", "vectorSearchScore"},
  				}},
  			}},
  		},
  	}

  	// Run the pipeline
  	cursor, err := coll.Aggregate(ctx, pipeline)
  	if err != nil {
  		log.Fatalf("failed to run aggregation: %v", err)
  	}
  	defer func() { _ = cursor.Close(ctx) }()

  	var matchingDocs []TextAndScore
  	if err = cursor.All(ctx, &matchingDocs); err != nil {
  		log.Fatalf("failed to unmarshal results to TextAndScore objects: %v", err)
  	}
  	for _, doc := range matchingDocs {
  		fmt.Printf("Text: %v\nScore: %v\n", doc.Text, doc.Score)
  	}
  }

  ```

